describe('_renderLockRow sync status rendering', () => {
    let card: SlotCardElement;

    beforeEach(async () => {
        card = document.createElement('lcm-slot') as SlotCardElement;
        card.setConfig({ config_entry_id: 'abc', slot: 1, type: 'custom:lcm-slot' });
        card.hass = createMockHassWithConnection();
        container.appendChild(card);
        await flush();
    });

    /* eslint-disable @typescript-eslint/no-explicit-any */
    it('renders synced state with check-circle icon', () => {
        const lock = {
            code: '1234',
            codeLength: undefined,
            entityId: 'lock.test',
            inSync: true,
            lastSynced: undefined,
            lockEntityId: 'lock.test',
            name: 'Test Lock',
            syncStatus: 'in_sync'
        };
        const result = (card as any)._renderLockRow(lock);
        const rendered = result.strings.join('');
        expect(rendered).toContain('lcm-sync-icon');
        expect(rendered).toContain('synced');
        expect(rendered).toContain('mdi:check-circle');
    });

    it('renders out_of_sync state with clock-outline icon', () => {
        const lock = {
            code: '1234',
            codeLength: undefined,
            entityId: 'lock.test',
            inSync: false,
            lastSynced: undefined,
            lockEntityId: 'lock.test',
            name: 'Test Lock',
            syncStatus: 'out_of_sync'
        };
        const result = (card as any)._renderLockRow(lock);
        const rendered = result.strings.join('');
        expect(rendered).toContain('pending');
        expect(rendered).toContain('mdi:clock-outline');
    });

    it('renders syncing state with sync icon', () => {
        const lock = {
            code: '1234',
            codeLength: undefined,
            entityId: 'lock.test',
            inSync: false,
            lastSynced: undefined,
            lockEntityId: 'lock.test',
            name: 'Test Lock',
            syncStatus: 'syncing'
        };
        const result = (card as any)._renderLockRow(lock);
        const rendered = result.strings.join('');
        expect(rendered).toContain('syncing');
        expect(rendered).toContain('mdi:sync');
    });

    it('renders suspended state with alert-circle icon', () => {
        const lock = {
            code: null,
            codeLength: undefined,
            entityId: 'lock.test',
            inSync: false,
            lastSynced: undefined,
            lockEntityId: 'lock.test',
            name: 'Test Lock',
            syncStatus: 'suspended'
        };
        const result = (card as any)._renderLockRow(lock);
        const rendered = result.strings.join('');
        expect(rendered).toContain('suspended');
        expect(rendered).toContain('mdi:alert-circle');
    });

    it('falls back to inSync boolean when syncStatus is undefined', () => {
        const lock = {
            code: '1234',
            codeLength: undefined,
            entityId: 'lock.test',
            inSync: false,
            lastSynced: undefined,
            lockEntityId: 'lock.test',
            name: 'Test Lock',
            syncStatus: undefined
        };
        const result = (card as any)._renderLockRow(lock);
        const rendered = result.strings.join('');
        expect(rendered).toContain('pending');
        expect(rendered).toContain('mdi:clock-outline');
    });

    it('renders unknown state when syncStatus undefined and inSync is null', () => {
        const lock = {
            code: null,
            codeLength: undefined,
            entityId: 'lock.test',
            inSync: null,
            lastSynced: undefined,
            lockEntityId: 'lock.test',
            name: 'Test Lock',
            syncStatus: undefined
        };
        const result = (card as any)._renderLockRow(lock);
        const rendered = result.strings.join('');
        expect(rendered).toContain('unknown');
        expect(rendered).toContain('mdi:help-circle');
    });

    it('shows status text instead of last-synced when suspended', () => {
        const lock = {
            code: null,
            codeLength: undefined,
            entityId: 'lock.test',
            inSync: false,
            lastSynced: '2026-04-20T12:00:00Z',
            lockEntityId: 'lock.test',
            name: 'Test Lock',
            syncStatus: 'suspended'
        };
        const result = (card as any)._renderLockRow(lock);
        const rendered = result.strings.join('');
        // Should show status text, not "Last synced to lock"
        expect(rendered).not.toContain('Last synced to lock');
    });
    /* eslint-enable @typescript-eslint/no-explicit-any */
});

